// โหลด state เดิม (ถ้ามี) หรือสร้างใหม่
let state;
try {
  state = JSON.parse($input.first().json.stateRaw || '{}');
} catch (e) {
  state = {};
}
state.history = state.history || [];
state.degree = state.degree || null;       // วุฒิการศึกษา
state.job = state.job || null;             // อาชีพ
state.experience = state.experience || null; // ประสบการณ์ทำงาน
state.major = state.major || null;         // สาขาที่สนใจ: นิติ/บัญชี/รัฐประศาสนศาสตร์

const userMessage = $('Webhook').first().json.body.message || '';
state.history.push({ role: 'user', content: userMessage });

const text = userMessage.toLowerCase();

// ----- ดึงสาขาที่สนใจ (deterministic, ไม่พึ่ง AI ตัดสินใจ) -----
if (!state.major) {
  if (text.includes('นิติ')) state.major = 'นิติศาสตร์';
  else if (text.includes('บัญชี')) state.major = 'บัญชี';
  else if (text.includes('รัฐประศาสน') || text.includes('รัฐ')) state.major = 'รัฐประศาสนศาสตร์';
}

// ----- ดึงวุฒิการศึกษา -----
if (!state.degree) {
  if (/ม\.?6|มัธยมศึกษาปีที่\s*6|มัธยมปลาย/.test(text)) state.degree = 'ม.6';
  else if (/ปวช/.test(text)) state.degree = 'ปวช.';
  else if (/ปวส/.test(text)) state.degree = 'ปวส.';
  else if (/ป\.?ตรี|ปริญญาตรี|bachelor/.test(text)) state.degree = 'ปริญญาตรี';
  else if (/ป\.?โท|ปริญญาโท|master/.test(text)) state.degree = 'ปริญญาโท';
}

// ----- ดึงอาชีพ/ประสบการณ์ (แบบหยาบ - เก็บข้อความที่เกี่ยวกับงาน) -----
if (!state.job && /ทำงาน|รับราชการ|พนักงาน|ธุรกิจส่วนตัว|อาชีพ/.test(text)) {
  state.job = userMessage;
}
if (!state.experience && /ปี|ปีแล้ว|ประสบการณ์/.test(text) && /ทำงาน|ปี/.test(text)) {
  state.experience = userMessage;
}

const infoComplete = !!(state.degree && state.job && state.experience);

return [{
  json: {
    ...state,
    infoComplete,
    userId: $('Webhook').first().json.body.userId
  }
}];

